test("operations workbench shows a loading state instead of stale source while switching campaigns", async ({ page }) => {
  const ormskirkId = "69f257b6-9913-4395-94f7-5c25b4b5fe95";
  const towerHamletsId = "57678ae0-29fd-4b4b-8a53-5c711cdb21cf";
  const barnetId = "6b54225d-afa3-41d1-b053-89741094f153";
  const campaigns: Record<string, { title: string; place: string; status: "partial" | "completed"; next: string }> = {
    [ormskirkId]: { title: "Keep KFC Out of Ormskirk", place: "Ormskirk, Lancashire", status: "partial", next: "Check Ormskirk appeal status" },
    [towerHamletsId]: { title: "Build 5,000 affordable houses in Tower Hamlets in the next 3 years", place: "Tower Hamlets, London", status: "partial", next: "Check Tower Hamlets housing target" },
    [barnetId]: { title: "Stop the leisure park redevelopment in Barnet", place: "Barnet, London", status: "completed", next: "Check Barnet committee records" },
  };
  let releaseBarnetSource: (() => void) | undefined;
  const barnetSourceGate = new Promise<void>((resolve) => {
    releaseBarnetSource = resolve;
  });

  await page.route(/\/api\/operations\/sources\/([^/]+)$/, async (route) => {
    const id = route.request().url().match(/sources\/([^/]+)$/)?.[1] ?? ormskirkId;
    if (id === barnetId) await barnetSourceGate;
    const campaign = campaigns[id] ?? campaigns[ormskirkId];
    await route.fulfill({
      contentType: "application/json",
      body: JSON.stringify({
        sourceOrigin: "https://campaign-factory.vercel.app",
        run: { campaignId: id, status: campaign.status, stateVersion: 8, lastSequence: 21, events: [] },
        documents: campaignOperationsDocuments(campaign),
        evidence: campaignEvidence([{ id: `switch-${id}`, description: campaign.next, reason: "Campaign switch stale-source regression", affectedSections: ["strategy"] }]),
      }),
    });
  });

  await page.goto(`/operations?campaignId=${ormskirkId}`);
  await expect(page.getByRole("heading", { name: "Keep KFC Out of Ormskirk" })).toBeVisible();

  await page.locator(`a[href="/operations?campaignId=${barnetId}&view=overview"]`).click();
  await expect(page.getByRole("heading", { name: "Loading campaign source" })).toBeVisible();
  await expect(page.getByText("Keep KFC Out of Ormskirk", { exact: true })).toHaveCount(0);

  releaseBarnetSource?.();
  await expect(page.getByRole("heading", { name: "Stop the leisure park redevelopment in Barnet" })).toBeVisible();
});

test("operations portfolio: one failed source does not blank usable campaigns", async ({ page }) => {
  const campaigns = {
    "69f257b6-9913-4395-94f7-5c25b4b5fe95": {
      title: "Keep KFC Out of Ormskirk",
      place: "Ormskirk, Lancashire",
      status: "partial",
      next: "Retrieve the official West Lancashire Borough Council planning application record",
      unresolved: 34,
    },
    "6b54225d-afa3-41d1-b053-89741094f153": {
      title: "Stop the leisure park redevelopment in Barnet",
      place: "Barnet, London",
      status: "completed",
      next: "Attempt direct retrieval of the GLA decision report and Barnet Council committee minutes",
      unresolved: 17,
    },
  } as const;

  await page.route(/\/api\/operations\/sources\/([^/]+)$/, async (route) => {
    const id = route.request().url().match(/sources\/([^/]+)$/)?.[1] as keyof typeof campaigns;
    if (id === "57678ae0-29fd-4b4b-8a53-5c711cdb21cf") {
      await route.fulfill({
        status: 429,
        headers: { "Retry-After": "90" },
        contentType: "application/json",
        body: JSON.stringify({ error: "Campaign source documents unavailable", detail: "Preview source returned HTTP 429.", runStatus: "partial", sourceOrigin: "https://campaign-factory.vercel.app", sourceStep: "documents", sourceHttpStatus: 429, sourceRequestId: "lhr1::iad1::portfolio-429" }),
      });
      return;
    }
    const campaign = campaigns[id];
    const documents = canonicalOperationsDocuments(campaign.title).map((document) =>
      document.key === "campaign_brief"
        ? {
            ...document,
            html: `<p>${withCompiledDocumentDisclaimer(`${campaign.title}\n\nPlace: ${campaign.place}\n\nTHE PROBLEM\nSource-backed campaign problem.`)}</p>`,
            plainText: withCompiledDocumentDisclaimer(`${campaign.title}\n\nPlace: ${campaign.place}\n\nTHE PROBLEM\nSource-backed campaign problem.`),
          }
        : document,
    );
    await route.fulfill({
      contentType: "application/json",
      body: JSON.stringify({
        sourceOrigin: "https://campaign-factory.vercel.app",
        run: { campaignId: id, status: campaign.status, stateVersion: 1, lastSequence: 1, events: [] },
        documents,
        evidence: {
          groups: [],
          conflicts: [],
          nextChecks: [{ id: "next", description: campaign.next, reason: "Portfolio next gate", claimIds: [], affectedSections: [] }],
          terminalGaps: [],
          draftNotes: [],
          totals: { claims: 0, loadBearing: 0, verifiedLoadBearing: 0, unresolvedLoadBearing: 0 },
        },
      }),
    });
  });

  await page.goto("/operations");

  await expect(page.getByRole("heading", { name: /Three real campaigns, one operations portfolio/i })).toBeVisible();
  await expect(page.getByText("Keep KFC Out of Ormskirk", { exact: true })).toBeVisible();
  await expect(page.getByText("Stop the leisure park redevelopment in Barnet", { exact: true })).toBeVisible();
  await expect(page.getByText("Campaign source unavailable", { exact: true })).toBeVisible();
  await expect(page.getByText(/Preview source returned HTTP 429/)).toBeVisible();
  await expect(page.getByText("Checked read-only source:")).toBeVisible();
  await expect(page.getByText("Source run status: Partial but usable")).toBeVisible();
  await expect(page.getByText("Failed source step:")).toBeVisible();
  await expect(page.getByText("compiled documents", { exact: true })).toBeVisible();
  await expect(page.getByText("Source response:")).toBeVisible();
  await expect(page.getByText("upstream HTTP 429 · request lhr1::iad1::portfolio-429")).toBeVisible();
  await expect(page.getByText(/Last source attempt/)).toBeVisible();
  await expect(page.getByText("Source retry guidance: try again after 90 seconds.")).toBeVisible();
  await expect(page.getByText("https://campaign-factory.vercel.app", { exact: true })).toBeVisible();
  await expect(page.getByRole("link", { name: "Open workspace" })).toHaveCount(3);
  await expect(page.getByRole("link", { name: "Open workspace" }).nth(0)).toHaveAttribute("href", "/operations?campaignId=69f257b6-9913-4395-94f7-5c25b4b5fe95");
  await expect(page.getByRole("link", { name: "Open workspace" }).nth(2)).toHaveAttribute("href", "/operations?campaignId=6b54225d-afa3-41d1-b053-89741094f153");
  await expect(page.getByRole("heading", { name: /Make the St John the Baptist school street/i })).toHaveCount(0);
  await expect(page.getByRole("link", { name: "View source brief" }).nth(1)).toHaveAttribute(
    "href",
    "https://campaign-factory.vercel.app/factory/c/57678ae0-29fd-4b4b-8a53-5c711cdb21cf",
  );
});

test("operations portfolio: not-yet-usable source rows show run status without fixture fallback", async ({ page }) => {
  await page.route(/\/api\/operations\/sources\/([^/]+)$/, async (route) => {
    const id = route.request().url().match(/sources\/([^/]+)$/)?.[1] ?? "";
    if (id === "57678ae0-29fd-4b4b-8a53-5c711cdb21cf") {
      await route.fulfill({
        status: 409,
        contentType: "application/json",
        body: JSON.stringify({
          error: "Campaign source not ready",
          detail: "This campaign is queued, so compiled operations source material is not available yet.",
          runStatus: "queued",
          sourceOrigin: "https://campaign-factory.vercel.app",
          sourceStep: "run",
          sourceFailureKind: "not_ready",
          sourcePath: `/api/factory/runs/${id}`,
          sourceHttpStatus: 200,
          sourceElapsedMs: 26,
          sourceRequestId: "lhr1::iad1::queued-run",
          sourceMatchedPath: "/api/factory/runs/[id]",
          sourceCacheStatus: "MISS",
          sourceContentType: "application/json",
        }),
      });
      return;
    }

    await route.fulfill({
      contentType: "application/json",
      body: JSON.stringify({
        sourceOrigin: "https://campaign-factory.vercel.app",
        run: { campaignId: id, status: "partial", stateVersion: 1, lastSequence: 1, events: [] },
        documents: canonicalOperationsDocuments(),
        evidence: campaignEvidence([{ id: `check-${id}`, description: "Confirm source-specific next check", reason: "Portfolio not-ready row regression", affectedSections: ["strategy"] }], 1),
      }),
    });
  });

  await page.goto("/operations");

  const portfolio = page.getByLabel("Campaign operations portfolio");
  const towerHamletsRow = portfolio.locator("article", { hasText: "Campaign not usable yet" });
  await expect(towerHamletsRow).toContainText("Source queued");
  await expect(towerHamletsRow).toContainText("This campaign is queued");
  await expect(towerHamletsRow).toContainText("Source run status: Queued");
  await expect(towerHamletsRow).toContainText("Failed source step: run header");
  await expect(towerHamletsRow).toContainText("Source response: source status not usable yet · upstream HTTP 200 · source fetch 26ms · request lhr1::iad1::queued-run · source path /api/factory/runs/57678ae0-29fd-4b4b-8a53-5c711cdb21cf · matched /api/factory/runs/[id] · cache MISS · upstream content type application/json");
  await expect(towerHamletsRow).toContainText("Local signals: no browser-local operations work yet for this campaign.");
  await expect(page.getByRole("heading", { name: /Make the St John the Baptist school street/i })).toHaveCount(0);
});

